after_code:
// product-service.ts
const cache = new Map<string, Product>();

export async function getProduct(id: string): Promise<Product> {
  if (cache.has(id)) return cache.get(id)!;
  const product = await db.products.findOne({ id });
  cache.set(id, product);
  return product;
}
